CREATE OR REPLACE FUNCTION upsert_and_return_strategy_master( p_strategy_id BIGINT, p_strategy_name VARCHAR(100), p_description VARCHAR(500), p_entity VARCHAR(20), p_product VARCHAR(50), p_function VARCHAR(100), p_region VARCHAR(50), p_owner VARCHAR(50), p_analysts JSONB, p_reviewers JSONB, p_status VARCHAR(20), p_created_by VARCHAR(50), p_updated_by VARCHAR(50) ) RETURNS SETOF sb_strategy_mstr LANGUAGE plpgsql AS $$ DECLARE v_strategy_id BIGINT; v_sub_strategy_id BIGINT; v_default_sub_strategy_name VARCHAR(100); v_is_new BOOLEAN := FALSE; v_actor VARCHAR(50); BEGIN -- actor performing the change: creator on create, updater on edit v_actor := COALESCE(p_updated_by, p_created_by);
------------------------------------------------------------------ -- 1. STRATEGY: update if it exists, otherwise insert (create) ------------------------------------------------------------------ IF p_strategy_id IS NOT NULL THEN UPDATE sb_strategy_mstr SET strategy_name = p_strategy_name, description = p_description, entity = p_entity, product = p_product, function = p_function, region = p_region, owner = p_owner, analysts = p_analysts, reviewers = p_reviewers, status = p_status, updated_by = p_updated_by, updated_at = CURRENT_TIMESTAMP WHERE strategy_id = p_strategy_id;
IF NOT FOUND THEN RAISE EXCEPTION 'Strategy with id % does not exist for update', p_strategy_id; END IF;
v_strategy_id := p_strategy_id; v_is_new := FALSE; ELSE INSERT INTO sb_strategy_mstr ( strategy_name, description, entity, product, function, region, owner, analysts, reviewers, status, created_by, updated_by, created_at, updated_at ) VALUES ( p_strategy_name, p_description, p_entity, p_product, p_function, p_region, p_owner, p_analysts, p_reviewers, p_status, p_created_by, p_created_by, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP ) RETURNING strategy_id INTO v_strategy_id;
v_is_new := TRUE; END IF;
------------------------------------------------------------------ -- 2. SUB-STRATEGY + 3. RUN: seed defaults on CREATE only ------------------------------------------------------------------ IF v_is_new THEN v_default_sub_strategy_name := LEFT(COALESCE(NULLIF(TRIM(p_strategy_name), ''), 'Default Strategy') || ' - Default', 100);
INSERT INTO sb_sub_strategy_mstr ( strategy_id, sub_strategy_name, description, created_by, updated_by, created_at, updated_at ) VALUES ( v_strategy_id, v_default_sub_strategy_name, NULL, p_created_by, p_created_by, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP ) RETURNING sub_strategy_id INTO v_sub_strategy_id;
INSERT INTO sb_run_mstr ( strategy_id, sub_strategy_id, run_name, status, module_name, module_status, setup_type, created_by, updated_by, created_at, updated_at ) VALUES ( v_strategy_id, v_sub_strategy_id, NULL, 'Draft', 'Data', 'Draft', 'Manual', p_created_by, p_created_by, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP ); END IF;
------------------------------------------------------------------ -- 4. ACCESS RECONCILIATION (runs on BOTH create and edit) -- Desired set = owner (OWNER) + analysts (ANALYST) + reviewers (REVIEWER). -- a) revoke active rows not in the desired set (handles role changes / removals) -- b) insert desired rows that have no active row yet (handles additions / role changes) ------------------------------------------------------------------
-- Build the desired (user_id, role) set into a temp structure via CTE reuse. -- (a) Revoke: any currently-active access row for this strategy whose (user_id, role) -- is NOT in the desired set. UPDATE sb_access_mstr a SET revoked_at = CURRENT_TIMESTAMP, revoked_by = v_actor WHERE a.strategy_id = v_strategy_id AND a.revoked_at IS NULL AND NOT EXISTS ( SELECT 1 FROM ( SELECT TRIM(p_owner) AS user_id, 'OWNER' AS role WHERE p_owner IS NOT NULL AND TRIM(p_owner) <> '' UNION ALL SELECT TRIM(value), 'ANALYST' FROM jsonb_array_elements_text(COALESCE(p_analysts, '[]'::jsonb)) WHERE TRIM(value) <> '' UNION ALL SELECT TRIM(value), 'REVIEWER' FROM jsonb_array_elements_text(COALESCE(p_reviewers, '[]'::jsonb)) WHERE TRIM(value) <> '' ) desired WHERE desired.user_id = a.user_id AND desired.role = UPPER(a.role) );
-- (b) Insert: any desired (user_id, role) that does not already have an ACTIVE row. INSERT INTO sb_access_mstr ( strategy_id, user_id, role, granted_by, granted_at, revoked_at, revoked_by ) SELECT DISTINCT v_strategy_id, desired.user_id, desired.role, v_actor, CURRENT_TIMESTAMP, NULL, NULL FROM ( SELECT TRIM(p_owner) AS user_id, 'OWNER'::VARCHAR(30) AS role WHERE p_owner IS NOT NULL AND TRIM(p_owner) <> '' UNION ALL SELECT TRIM(value), 'ANALYST'::VARCHAR(30) FROM jsonb_array_elements_text(COALESCE(p_analysts, '[]'::jsonb)) WHERE TRIM(value) <> '' UNION ALL SELECT TRIM(value), 'REVIEWER'::VARCHAR(30) FROM jsonb_array_elements_text(COALESCE(p_reviewers, '[]'::jsonb)) WHERE TRIM(value) <> '' ) desired WHERE NOT EXISTS ( SELECT 1 FROM sb_access_mstr a WHERE a.strategy_id = v_strategy_id AND a.user_id = desired.user_id AND UPPER(a.role) = desired.role AND a.revoked_at IS NULL );
------------------------------------------------------------------ -- 5. RETURN the resulting strategy row ------------------------------------------------------------------ RETURN QUERY SELECT * FROM sb_strategy_mstr WHERE strategy_id = v_strategy_id; END; $$;
